import { createClient } from '@/lib/supabase/server';
import { notFound } from 'next/navigation';
import { Book as BookIcon, User, Globe, FileText, ArrowLeft, Tag } from 'lucide-react';
import Link from 'next/link';

export async function generateMetadata({ params }: { params: { slug: string } }) {
  const supabase = await createClient();
  const { data } = await supabase
    .from('books')
    .select('title, summary')
    .eq('slug', params.slug)
    .single();

  if (!data) return { title: 'Not Found' };

  return {
    title: `${data.title} | Library | Advaitha Yogam`,
    description: data.summary?.substring(0, 160) || 'Spiritual book from the library',
  };
}

export default async function BookEntryPage({ params }: { params: { slug: string } }) {
  const supabase = await createClient();
  
  const { data: book, error } = await supabase
    .from('books')
    .select('*')
    .eq('slug', params.slug)
    .single();

  if (error || !book) {
    notFound();
  }

  return (
    <div className="min-h-screen bg-[#FAFAFA] py-12 px-4 sm:px-6 lg:px-8 font-[family-name:var(--font-outfit)]">
      <div className="max-w-4xl mx-auto">
        <Link href="/books" className="inline-flex items-center gap-2 text-sm font-medium text-gray-500 hover:text-[#2D5A3D] transition-colors mb-8">
          <ArrowLeft size={16} /> Back to Library
        </Link>
        
        <div className="bg-white rounded-3xl overflow-hidden shadow-sm border border-gray-100 flex flex-col md:flex-row">
          {/* Book Cover Side */}
          <div className="md:w-1/3 bg-[#2D5A3D]/5 p-8 flex flex-col items-center justify-center border-b md:border-b-0 md:border-r border-gray-100">
            <div className="w-48 md:w-full max-w-[240px] aspect-[2/3] bg-white rounded-lg shadow-md overflow-hidden relative mb-8 flex-shrink-0 border border-gray-200/50">
              {book.cover_url ? (
                <img src={book.cover_url} alt={book.title} className="w-full h-full object-cover" />
              ) : (
                <div className="w-full h-full flex flex-col items-center justify-center bg-gradient-to-br from-[#2D5A3D]/10 to-[#2D5A3D]/30 p-4 text-center">
                  <BookIcon className="w-12 h-12 text-[#2D5A3D]/40 mb-3" />
                  <span className="font-[family-name:var(--font-cormorant)] text-[#2D5A3D] font-bold leading-tight">{book.title}</span>
                </div>
              )}
            </div>
            
            {book.pdf_url && (
              <a 
                href={book.pdf_url} 
                target="_blank" 
                rel="noreferrer"
                className="w-full flex items-center justify-center gap-2 px-6 py-3 bg-[#2D5A3D] hover:bg-[#1a3825] text-white font-medium rounded-xl transition-all shadow-md hover:shadow-lg transform hover:-translate-y-0.5"
              >
                <FileText size={18} />
                Read PDF
              </a>
            )}
          </div>
          
          {/* Book Details Side */}
          <div className="md:w-2/3 p-8 md:p-12 flex flex-col">
            <div className="flex flex-wrap gap-2 mb-4">
              {book.genre && (
                <span className="inline-flex items-center text-xs font-bold tracking-wider uppercase text-[#2D5A3D] bg-[#2D5A3D]/10 px-3 py-1 rounded-full">
                  {book.genre}
                </span>
              )}
            </div>
            
            <h1 className="text-3xl md:text-5xl font-bold font-[family-name:var(--font-cormorant)] text-gray-900 mb-6 leading-tight">
              {book.title}
            </h1>
            
            <div className="flex flex-col gap-3 mb-8 pb-8 border-b border-gray-100">
              {book.author && (
                <div className="flex items-center gap-3 text-gray-700">
                  <div className="w-8 h-8 rounded-full bg-amber-100 flex items-center justify-center text-amber-700">
                    <User size={16} />
                  </div>
                  <span className="font-medium text-lg">{book.author}</span>
                </div>
              )}
              
              <div className="flex items-center gap-3 text-gray-600">
                <div className="w-8 h-8 rounded-full bg-blue-50 flex items-center justify-center text-blue-600">
                  <Globe size={16} />
                </div>
                <span className="capitalize">{book.language || 'English'}</span>
              </div>
            </div>
            
            <div className="flex-1">
              <h3 className="text-xl font-bold font-[family-name:var(--font-cormorant)] text-gray-900 mb-4">About this text</h3>
              {book.summary ? (
                <div className="prose prose-emerald max-w-none text-gray-700 leading-relaxed font-[family-name:var(--font-outfit)]">
                  {book.summary.split('\n').map((paragraph: string, idx: number) => (
                    paragraph.trim() ? <p key={idx}>{paragraph}</p> : <br key={idx} />
                  ))}
                </div>
              ) : (
                <p className="text-gray-500 italic">No summary available for this text yet.</p>
              )}
            </div>

            {book.tags && book.tags.length > 0 && (
              <div className="mt-10 pt-8 border-t border-gray-100">
                <div className="flex flex-wrap gap-2">
                  {book.tags.map((tag: string) => (
                    <span key={tag} className="inline-flex items-center gap-1.5 text-xs font-medium text-gray-600 bg-gray-100 px-3 py-1.5 rounded-lg hover:bg-gray-200 transition-colors cursor-default">
                      <Tag size={12} /> {tag}
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
